// Shared TRAQS logo assets — high-res PNGs cropped from the official brand wordmark
// with the cream / black backgrounds knocked out so the wordmark sits on any UI surface.
// The "WHITE" variant is the cream wordmark intended for dark surfaces, the "BLUE"
// variant is the black wordmark intended for light surfaces. UL_LOGO_WHITE is the
// rendering target throughout the app (header, login, Fast TRAQS) and is theme-flipped
// via CSS filter: brightness(0) on light themes.
export const TRAQS_LOGO_BLUE  = "data:image/png;base64,";
export const TRAQS_LOGO_WHITE = "data:image/png;base64,";
export const UL_LOGO_WHITE    = "data:image/png;base64,";
